using System;
using System.Reflection;
using System.Linq;

// Load the assemblies directly
var agentsPath = "/home/runner/.nuget/packages/microsoft.agents.ai/1.6.2/lib/net10.0/Microsoft.Agents.AI.dll";
var extensionsPath = "/home/runner/.nuget/packages/microsoft.extensions.ai/10.3.0/lib/net10.0/Microsoft.Extensions.AI.dll";

var agentsAsm = Assembly.LoadFrom(agentsPath);
var extensionsAsm = Assembly.LoadFrom(extensionsPath);

Console.WriteLine("========================================");
Console.WriteLine("MICROSOFT.AGENTS.AI ASSEMBLY");
Console.WriteLine("========================================\n");

// Key types to explore
var keyTypes = new[] { 
    "Microsoft.Agents.AI.ChatClientAgent",
    "Microsoft.Agents.AI.AgentInvokeOptions",
};

foreach (var typeName in keyTypes)
{
    var type = agentsAsm.GetType(typeName);
    if (type == null)
    {
        Console.WriteLine($"❌ Type not found: {typeName}\n");
        continue;
    }

    Console.WriteLine($">>> {type.FullName}");
    Console.WriteLine();

    // Constructors
    var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (ctors.Length > 0)
    {
        Console.WriteLine("CONSTRUCTORS:");
        foreach (var ctor in ctors)
        {
            var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"  {type.Name}({parms})");
        }
        Console.WriteLine();
    }

    // Properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    if (props.Length > 0)
    {
        Console.WriteLine("PROPERTIES:");
        foreach (var prop in props)
        {
            var access = "";
            if (prop.CanRead) access += "get;";
            if (prop.CanWrite) access += " set;";
            Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} {{ {access} }}");
        }
        Console.WriteLine();
    }

    // Methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name)
        .ToArray();
    if (methods.Length > 0)
    {
        Console.WriteLine("METHODS:");
        foreach (var method in methods)
        {
            var parms = string.Join(", ", method.GetParameters().Select(p => 
            {
                var typeName = p.ParameterType.IsGenericType 
                    ? p.ParameterType.Name.Split('`')[0] + "<" + string.Join(",", p.ParameterType.GetGenericArguments().Select(ga => ga.Name)) + ">"
                    : p.ParameterType.Name;
                return $"{typeName} {p.Name}";
            }));
            var retType = method.ReturnType.IsGenericType 
                ? method.ReturnType.Name.Split('`')[0] + "<" + string.Join(",", method.ReturnType.GetGenericArguments().Select(ga => ga.Name)) + ">"
