using System;
using System.Reflection;
using System.Linq;
using Microsoft.Agents.AI;

// Explore ChatClientAgent
var agentType = typeof(ChatClientAgent);
Console.WriteLine(">>> ChatClientAgent");
Console.WriteLine($"Type: {agentType.FullName}\n");

// Constructors
var ctors = agentType.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
Console.WriteLine("CONSTRUCTORS:");
foreach (var ctor in ctors)
{
    var parms = string.Join(", ", ctor.GetParameters().Select(p => 
    {
        var ptype = p.ParameterType;
        var typeName = ptype.IsGenericType 
            ? ptype.Name.Split('`')[0] + "<" + string.Join(",", ptype.GetGenericArguments().Select(ga => ga.Name)) + ">"
            : ptype.Name;
        var hasDefault = p.HasDefaultValue ? $" = {p.DefaultValue}" : "";
        return $"{typeName} {p.Name}{hasDefault}";
    }));
    Console.WriteLine($"  ChatClientAgent({parms})");
}
Console.WriteLine();

// Properties
var props = agentType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
if (props.Length > 0)
{
    Console.WriteLine("PROPERTIES:");
    foreach (var prop in props.OrderBy(p => p.Name))
    {
        var access = "";
        if (prop.CanRead) access += "get;";
        if (prop.CanWrite) access += " set;";
        var propType = prop.PropertyType;
        var typeName = propType.IsGenericType 
            ? propType.Name.Split('`')[0] + "<" + string.Join(",", propType.GetGenericArguments().Select(ga => ga.Name)) + ">"
            : propType.Name;
        Console.WriteLine($"  {typeName} {prop.Name} {{ {access} }}");
    }
    Console.WriteLine();
}

// Methods - focus on Invoke, InvokeAsync, InvokeStreaming
var methods = agentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
    .Where(m => !m.IsSpecialName && (m.Name.Contains("Invoke") || m.Name.Contains("invoke")))
    .OrderBy(m => m.Name)
    .ToArray();

if (methods.Length > 0)
{
    Console.WriteLine("KEY METHODS (Invoke*):");
    foreach (var method in methods)
    {
        var parms = string.Join(", ", method.GetParameters().Select(p => 
        {
            var ptype = p.ParameterType;
            var typeName = ptype.IsGenericType 
                ? ptype.Name.Split('`')[0] + "<" + string.Join(",", ptype.GetGenericArguments().Select(ga => ga.Name)) + ">"
                : ptype.Name;
            var hasDefault = p.HasDefaultValue ? $" = {p.DefaultValue}" : "";
            return $"{typeName} {p.Name}{hasDefault}";
        }));
        var retType = method.ReturnType;
        var retTypeName = retType.IsGenericType 
            ? retType.Name.Split('`')[0] + "<" + string.Join(",", retType.GetGenericArguments().Select(ga => ga.Name)) + ">"
            : retType.Name;
        Console.WriteLine($"  {retTypeName} {method.Name}({parms})");
    }
    Console.WriteLine();
}

// Now explore AgentInvokeOptions
Console.WriteLine("\n>>> AgentInvokeOptions");
try
{
    var optionsType = agentType.Assembly.GetType("Microsoft.Agents.AI.AgentInvokeOptions");
    if (optionsType != null)
    {
        Console.WriteLine($"Type: {optionsType.FullName}\n");

        // Constructors
        var optCtors = optionsType.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (optCtors.Length > 0)
        {
            Console.WriteLine("CONSTRUCTORS:");
            foreach (var ctor in optCtors)
            {
                var parms = string.Join(", ", ctor.GetParameters().Select(p => 
                {
                    var ptype = p.ParameterType;
                    var typeName = ptype.IsGenericType 
                        ? ptype.Name.Split('`')[0] + "<" + string.Join(",", ptype.GetGenericArguments().Select(ga => ga.Name)) + ">"
                        : ptype.Name;
                    return $"{typeName} {p.Name}";
                }));
                Console.WriteLine($"  AgentInvokeOptions({parms})");
            }
            Console.WriteLine();
        }

        // Properties
        var optProps = optionsType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
        if (optProps.Length > 0)
        {
            Console.WriteLine("PROPERTIES:");
            foreach (var prop in optProps.OrderBy(p => p.Name))
            {
                var access = "";
                if (prop.CanRead) access += "get;";
                if (prop.CanWrite) access += " set;";
                var propType = prop.PropertyType;
                var typeName = propType.IsGenericType 
                    ? propType.Name.Split('`')[0] + "<" + string.Join(",", propType.GetGenericArguments().Select(ga => ga.Name)) + ">"
                    : propType.Name;
                Console.WriteLine($"  {typeName} {prop.Name} {{ {access} }}");
            }
            Console.WriteLine();
        }
    }
}
catch (Exception ex)
{
    Console.WriteLine($"Error exploring AgentInvokeOptions: {ex.Message}");
}

