using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tool state ---------------------------------------------------------------

var notebook = new ResearchNotebook();

// --- Define tools -------------------------------------------------------------

var searchTool = AIFunctionFactory.Create(
    notebook.SearchWeb,
    name: "search_web",
    description: "Search the web for information on a query. Returns a list of results with titles, snippets, and URLs.");

var saveNoteTool = AIFunctionFactory.Create(
    notebook.SaveNote,
    name: "save_note",
    description: "Save a research note with a title and body. Use this to record key findings during research.");

var getNotesTool = AIFunctionFactory.Create(
    notebook.GetNotes,
    name: "get_notes",
    description: "Retrieve all saved research notes. Use this to review collected findings before writing a summary.");

// --- Build the agent ----------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web 2-3 times with varied queries to gather broad information.
        2. Save the most important findings as notes (at least 3 notes).
        3. Retrieve your notes and write a well-structured summary with key points.
        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: [searchTool, saveNoteTool, getNotesTool]);

// --- Run the agent ------------------------------------------------------------

var topic = args.Length > 0
    ? string.Join(' ', args)
    : "the impact of large language models on software engineering in 2025";

Console.WriteLine($"🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync(CancellationToken.None);

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary:\n\n{topic}",
    session,
    options: null,
    cancellationToken: CancellationToken.None))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n--- Research complete ---");

// --- Tool implementations -----------------------------------------------------

/// <summary>Provides web-search and note-taking capabilities for the research agent.</summary>
sealed class ResearchNotebook
{
    private readonly List<Note> _notes = [];
    private readonly HttpClient _http = new();
    private static readonly JsonSerializerOptions s_jsonOptions = new() { WriteIndented = true };

    /// <summary>Search the web for information.</summary>
    [Description("Search the web for information on a query.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await _http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<object>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add(new { Title = abstractSource, Snippet = abstractText, Url = abstractUrl });
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var firstUrl))
                    {
                        results.Add(new
                        {
                            Title = text.GetString()?[..Math.Min(text.GetString()!.Length, 80)],
                            Snippet = text.GetString(),
                            Url = firstUrl.GetString()
                        });
                    }
                }
            }

            if (results.Count == 0)
            {
                results.Add(new
                {
                    Title = "Web search",
                    Snippet = $"No structured results found for '{query}'. Try a more specific query.",
                    Url = $"https://duckduckgo.com/?q={encoded}"
                });
            }

            return JsonSerializer.Serialize(results, s_jsonOptions);
        }
        catch (Exception ex)
        {
            return JsonSerializer.Serialize(new { Error = ex.Message, Query = query });
        }
    }

    /// <summary>Save a research note.</summary>
    [Description("Save a research note with a title and body.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content with findings")] string body)
    {
        _notes.Add(new Note(title, body, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    /// <summary>Retrieve all saved notes.</summary>
    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        var output = _notes.Select((n, i) => new
        {
            Number = i + 1,
            n.Title,
            n.Body,
            SavedAt = n.SavedAt.ToString("u")
        });
        return JsonSerializer.Serialize(output, s_jsonOptions);
    }

    private sealed record Note(string Title, string Body, DateTime SavedAt);
}

