+                            Url = firstUrl.GetString()
+                        });
+                    }
+                }
+            }
+
+            if (results.Count == 0)
+            {
+                results.Add(new
+                {
+                    Title = "Web search",
+                    Snippet = $"No structured results found for '{query}'. Try a more specific query.",
+                    Url = $"https://duckduckgo.com/?q={encoded}"
+                });
+            }
+
+            return JsonSerializer.Serialize(results, s_jsonOptions);
+        }
+        catch (Exception ex)
+        {
+            return JsonSerializer.Serialize(new { Error = ex.Message, Query = query });
+        }
+    }
+
+    /// <summary>Save a research note.</summary>
+    [Description("Save a research note with a title and body.")]
+    public string SaveNote(
+        [Description("Short title for the note")] string title,
+        [Description("The note content with findings")] string body)
+    {
+        _notes.Add(new Note(title, body, DateTime.UtcNow));
+        Console.WriteLine($"  📝 Note saved: \"{title}\"");
+        return $"Note #{_notes.Count} saved: \"{title}\"";
+    }
+
+    /// <summary>Retrieve all saved notes.</summary>
+    [Description("Retrieve all saved research notes.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes saved yet.";
+
+        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
+        var output = _notes.Select((n, i) => new
+        {
+            Number = i + 1,
+            n.Title,
+            n.Body,
+            SavedAt = n.SavedAt.ToString("u")
+        });
+        return JsonSerializer.Serialize(output, s_jsonOptions);
+    }
+
+    private sealed record Note(string Title, string Body, DateTime SavedAt);
+}
